Your registration endpoint likely has critical input validation flaws. The 2024 Twilio Authy breach (CVE-2024-39891) exposed 33 million phone numbers because their API accepted arbitrary input without proper validation or rate limiting. Attackers enumerated registered phone numbers, enabling targeted SIM-swap attacks against cryptocurrency holders.

**VULNERABLE CODE**:

```javascript
const express = require('express');
const bcrypt = require('bcrypt');
const db = require('./database');

const app = express();
app.use(express.json());

// VULNERABLE: No input validation whatsoever
app.post('/api/register', async (req, res) => {
  const { username, email, password, age, phoneNumber } = req.body;

  // Directly using user input without validation
  const hashedPassword = await bcrypt.hash(password, 10);

  const query = `
    INSERT INTO users (username, email, password, age, phone_number)
    VALUES ($1, $2, $3, $4, $5)
    RETURNING id
  `;

  try {
    const result = await db.query(query, [
      username,
      email,
      hashedPassword,
      age,
      phoneNumber
    ]);

    res.json({ success: true, userId: result.rows[0].id });
  } catch (error) {
    res.status(500).json({ error: error.message }); // Leaks internal errors
  }
});

app.listen(3000);
```

**Attack Payloads**:
```text
// Mass enumeration attack
POST /api/register with sequential phone numbers:
+1555000001, +1555000002, +1555000003...

// Malformed data injection
{
  "username": "<script>alert('xss')</script>",
  "email": "not-an-email",
  "password": "1",
  "age": -500,
  "phoneNumber": "'); DROP TABLE users;--"
}

// Business logic abuse
{
  "username": "admin",
  "email": "attacker@evil.com",
  "password": "password123",
  "age": 999999999999999999999,
  "phoneNumber": "+0000000000000000000000000000"
}
```

**Why This Is Dangerous**:
- No validation allows XSS payloads in usernames stored and later rendered
- Missing email format validation enables account enumeration and spam
- No password complexity requirements leads to easily crackable credentials
- Unbounded numeric fields can cause integer overflow or database errors
- Phone number without validation enables mass enumeration attacks
- Error messages leak internal database structure to attackers

**SECURE VERSION**:

```javascript
const express = require('express');
const bcrypt = require('bcrypt');
const { body, validationResult } = require('express-validator');
const sanitizeHtml = require('sanitize-html');
const db = require('./database');

const app = express();
app.use(express.json({ limit: '10kb' })); // Limit payload size

// Input validation middleware
const registrationValidation = [
  body('username')
    .trim()
    .isLength({ min: 3, max: 30 })
    .matches(/^[a-zA-Z0-9_]+$/)
    .withMessage('Username must be 3-30 alphanumeric characters'),

  body('email')
    .trim()
    .isEmail()
    .normalizeEmail()
    .isLength({ max: 255 })
    .withMessage('Valid email required'),

  body('password')
    .isLength({ min: 12, max: 128 })
    .matches(/^(?=.*[a-z])(?=.*[A-Z])(?=.*\d)(?=.*[@$!%*?&])/)
    .withMessage('Password must be 12+ chars with uppercase, lowercase, number, and symbol'),

  body('age')
    .isInt({ min: 13, max: 120 })
    .withMessage('Age must be between 13 and 120'),

  body('phoneNumber')
    .matches(/^\+[1-9]\d{6,14}$/)
    .withMessage('Valid E.164 phone number required')
];

app.post('/api/register', registrationValidation, async (req, res) => {
  // Check validation results
  const errors = validationResult(req);
  if (!errors.isEmpty()) {
    return res.status(400).json({
      success: false,
      errors: errors.array().map(e => e.msg) // Don't expose field names
    });
  }

  const { username, email, password, age, phoneNumber } = req.body;

  // Additional sanitization
  const sanitizedUsername = sanitizeHtml(username, { allowedTags: [] });

  const hashedPassword = await bcrypt.hash(password, 12);

  try {
    const result = await db.query(
      `INSERT INTO users (username, email, password, age, phone_number)
       VALUES ($1, $2, $3, $4, $5) RETURNING id`,
      [sanitizedUsername, email, hashedPassword, age, phoneNumber]
    );

    res.status(201).json({ success: true, userId: result.rows[0].id });
  } catch (error) {
    console.error('Registration error:', error); // Log internally
    res.status(500).json({ success: false, error: 'Registration failed' });
  }
});
```

**Key Security Controls**:
- **Input validation with express-validator**: Enforces type, format, and length constraints before processing
- **HTML sanitization**: Removes any HTML/script tags to prevent stored XSS
- **Password complexity requirements**: Enforces strong passwords that resist brute-force attacks
- **E.164 phone validation**: Only accepts valid international phone number format
- **Generic error messages**: Prevents information leakage about internal state

Excellent question! Enumeration attacks were exactly how the Twilio breach happened - attackers could determine which phone numbers were registered. You need rate limiting, consistent responses, and validation that doesn't leak information about existing accounts.

**PRODUCTION PATTERN**:

```javascript
const express = require('express');
const bcrypt = require('bcrypt');
const { body, validationResult } = require('express-validator');
const rateLimit = require('express-rate-limit');
const RedisStore = require('rate-limit-redis');
const Redis = require('ioredis');
const winston = require('winston');
const crypto = require('crypto');

const app = express();
const redis = new Redis(process.env.REDIS_URL);

// Structured logging for security events
const logger = winston.createLogger({
  level: 'info',
  format: winston.format.json(),
  transports: [
    new winston.transports.File({ filename: 'security-audit.log' })
  ]
});

// Rate limiting to prevent enumeration
const registrationLimiter = rateLimit({
  store: new RedisStore({ client: redis }),
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 5, // 5 attempts per window
  standardHeaders: true,
  legacyHeaders: false,
  handler: (req, res) => {
    logger.warn('Rate limit exceeded', {
      ip: req.ip,
      path: req.path,
      timestamp: new Date().toISOString()
    });
    res.status(429).json({
      success: false,
      error: 'Too many requests. Please try again later.'
    });
  }
});

// Custom validators for complex business rules
const customValidators = {
  isValidAddress: (value) => {
    if (!value || typeof value !== 'object') return false;
    const required = ['street', 'city', 'state', 'zip', 'country'];
    return required.every(field => 
      value[field] && 
      typeof value[field] === 'string' &&
      value[field].length <= 100
    );
  },

  isValidZipForCountry: (zip, { req }) => {
    const country = req.body.address?.country;
    const patterns = {
      'US': /^\d{5}(-\d{4})?$/,
      'UK': /^[A-Z]{1,2}\d[A-Z\d]? ?\d[A-Z]{2}$/i,
      'CA': /^[A-Z]\d[A-Z] ?\d[A-Z]\d$/i
    };
    return patterns[country]?.test(zip) ?? /^[A-Za-z0-9\s-]{3,10}$/.test(zip);
  },

  isNotDisposableEmail: async (email) => {
    const domain = email.split('@')[1];
    const disposable = await redis.sismember('disposable_domains', domain);
    if (disposable) throw new Error('Disposable emails not allowed');
    return true;
  }
};

// Comprehensive validation schema
const fullRegistrationValidation = [
  body('username')
    .trim()
    .isLength({ min: 3, max: 30 })
    .matches(/^[a-zA-Z0-9_]+$/)
    .custom(async (value) => {
      // Constant-time check to prevent timing attacks
      const exists = await db.query(
        'SELECT 1 FROM users WHERE username = $1', [value]
      );
      // Don't reveal if username exists
      return true;
    }),

  body('email')
    .trim()
    .isEmail()
    .normalizeEmail()
    .custom(customValidators.isNotDisposableEmail),

  body('password')
    .isLength({ min: 12, max: 128 })
    .custom((value, { req }) => {
      // Check password isn't similar to username or email
      const username = req.body.username?.toLowerCase();
      const email = req.body.email?.toLowerCase();
      const pwd = value.toLowerCase();

      if (username && pwd.includes(username)) {
        throw new Error('Password cannot contain username');
      }
      if (email && pwd.includes(email.split('@')[0])) {
        throw new Error('Password cannot contain email');
      }
      return true;
    }),

  body('address')
    .optional()
    .custom(customValidators.isValidAddress)
    .withMessage('Invalid address format'),

  body('address.zip')
    .optional()
    .custom(customValidators.isValidZipForCountry)
    .withMessage('Invalid postal code for country')
];

app.post('/api/register', 
  registrationLimiter,
  fullRegistrationValidation,
  async (req, res) => {
    const requestId = crypto.randomUUID();
    const startTime = Date.now();

    const errors = validationResult(req);
    if (!errors.isEmpty()) {
      logger.info('Validation failed', {
        requestId,
        ip: req.ip,
        errors: errors.array().length // Log count, not details
      });

      // Constant response time to prevent timing attacks
      await artificialDelay(startTime, 500);

      return res.status(400).json({
        success: false,
        error: 'Invalid input provided'
      });
    }

    try {
      // Check for existing user (constant time)
      const existing = await db.query(
        `SELECT email, username FROM users 
         WHERE email = $1 OR username = $2`,
        [req.body.email, req.body.username]
      );

      // CRITICAL: Same response whether user exists or not
      if (existing.rows.length > 0) {
        logger.warn('Duplicate registration attempt', {
          requestId,
          ip: req.ip,
          hashedEmail: hashForLog(req.body.email)
        });
      } else {
        // Actually create the user
        await createUser(req.body);
      }

      // Same response regardless of outcome
      await artificialDelay(startTime, 500);
      res.status(200).json({
        success: true,
        message: 'If this email is not registered, you will receive a confirmation.'
      });

    } catch (error) {
      logger.error('Registration error', {
        requestId,
        error: error.message
      });

      await artificialDelay(startTime, 500);
      res.status(200).json({
        success: true,
        message: 'If this email is not registered, you will receive a confirmation.'
      });
    }
  }
);

// Helper: Ensure consistent response time
async function artificialDelay(startTime, targetMs) {
  const elapsed = Date.now() - startTime;
  if (elapsed < targetMs) {
    await new Promise(r => setTimeout(r, targetMs - elapsed));
  }
}

// Helper: Hash values for logging without exposing PII
function hashForLog(value) {
  return crypto.createHash('sha256').update(value).digest('hex').slice(0, 8);
}

// Monitoring endpoint for security team
app.get('/internal/metrics', authenticateInternal, async (req, res) => {
  const metrics = await redis.hgetall('registration_metrics');
  res.json({
    totalAttempts: metrics.total || 0,
    rateLimitHits: metrics.rate_limited || 0,
    validationFailures: metrics.validation_failed || 0,
    duplicateAttempts: metrics.duplicates || 0
  });
});
```

**Defense in Depth Layers**:

1. **Anti-enumeration through constant-time responses**:
```javascript
// Always return the same response format and timing
const RESPONSE_TIME_MS = 500;
await artificialDelay(startTime, RESPONSE_TIME_MS);
res.json({ message: 'Check your email for confirmation' });
// Attacker cannot tell if account exists
```

2. **Distributed rate limiting with Redis**:
```javascript
// Per-IP and per-endpoint limits
const ipLimiter = rateLimit({
  store: new RedisStore({ client: redis, prefix: 'rl:ip:' }),
  keyGenerator: (req) => req.ip,
  max: 100,
  windowMs: 60000
});

const endpointLimiter = rateLimit({
  store: new RedisStore({ client: redis, prefix: 'rl:endpoint:' }),
  keyGenerator: (req) => `${req.ip}:${req.path}`,
  max: 10,
  windowMs: 60000
});
```

3. **Context-aware validation**:
```javascript
// Validate fields in context of each other
body('confirmPassword').custom((value, { req }) => {
  if (value !== req.body.password) {
    throw new Error('Passwords must match');
  }
  return true;
});

body('birthDate').custom((value) => {
  const age = calculateAge(new Date(value));
  if (age < 13 || age > 120) {
    throw new Error('Invalid birth date');
  }
  return true;
});
```

**Additional Protections**:
- **CAPTCHA integration**: Add reCAPTCHA or hCaptcha after 3 failed attempts to stop automated enumeration
- **Email verification flow**: Never confirm account creation until email is verified
- **Honeypot fields**: Add hidden fields that bots fill out but humans don't
- **Security headers**: Set X-Content-Type-Options, X-Frame-Options, Content-Security-Policy
- **Request signing**: For mobile apps, sign requests to prevent replay attacks
- **Anomaly detection**: Alert on unusual patterns (many registrations from same IP range, sequential phone numbers)

Basic null checking is absolutely NOT sufficient for user input validation. Missing proper input validation is a critical design flaw that can lead to data corruption, business logic bypass, and security breaches. The 2023 MOVEit breach demonstrated how missing input validation allowed attackers to bypass controls affecting millions of users.

**VULNERABLE CODE**:

```java
import javax.servlet.http.*;
import java.sql.*;

public class UserRegistrationServlet extends HttpServlet {

    private static final String DB_URL = "jdbc:postgresql://localhost/userdb";
    private static final String DB_USER = "appuser";
    private static final String DB_PASS = "password123";

    @Override
    protected void doPost(HttpServletRequest request, HttpServletResponse response) {
        String username = request.getParameter("username");
        String email = request.getParameter("email");
        String age = request.getParameter("age");
        String role = request.getParameter("role");

        // DANGEROUS: Only null checks - no real validation
        if (username != null && email != null && age != null) {
            try (Connection conn = DriverManager.getConnection(DB_URL, DB_USER, DB_PASS)) {
                String sql = "INSERT INTO users (username, email, age, role) VALUES (?, ?, ?, ?)";
                PreparedStatement stmt = conn.prepareStatement(sql);
                stmt.setString(1, username);
                stmt.setString(2, email);
                stmt.setInt(3, Integer.parseInt(age));
                stmt.setString(4, role != null ? role : "user");
                stmt.executeUpdate();
                response.getWriter().write("User registered successfully");
            } catch (Exception e) {
                response.setStatus(500);
            }
        }
    }
}
```

**Attack Payloads**:

```text
# Privilege escalation via role manipulation
username=hacker&email=a@b.com&age=25&role=admin

# Age manipulation for business logic bypass
username=test&email=test@test.com&age=-1&role=user

# Malicious username with special characters
username=<script>alert('xss')</script>&email=test@test.com&age=25

# Email with invalid format for spam/abuse
username=spammer&email=not-an-email&age=25
```

**Why This Is Dangerous**:
- Users can self-assign admin role by manipulating the role parameter
- Invalid age values (-1, 999) can break business logic and reports
- No email format validation allows fake accounts and spam vectors
- No username restrictions allow XSS payloads and SQL-like strings
- Integer.parseInt can throw NumberFormatException crashing the app

**SECURE VERSION**:

```java
import javax.servlet.http.*;
import java.sql.*;
import java.util.regex.*;
import java.util.logging.*;

public class SecureUserRegistrationServlet extends HttpServlet {

    private static final Logger logger = Logger.getLogger(SecureUserRegistrationServlet.class.getName());
    private static final String DB_URL = "jdbc:postgresql://localhost/userdb";
    private static final String DB_USER = "appuser";
    private static final String DB_PASS = "password123";

    // Validation patterns
    private static final Pattern USERNAME_PATTERN = Pattern.compile("^[a-zA-Z0-9_]{3,20}$");
    private static final Pattern EMAIL_PATTERN = Pattern.compile(
        "^[A-Za-z0-9+_.-]+@[A-Za-z0-9.-]+\\.[A-Za-z]{2,}$");
    private static final int MIN_AGE = 13;
    private static final int MAX_AGE = 120;

    @Override
    protected void doPost(HttpServletRequest request, HttpServletResponse response) {
        try {
            // DEFENSE 1: Extract and validate all inputs
            String username = validateUsername(request.getParameter("username"));
            String email = validateEmail(request.getParameter("email"));
            int age = validateAge(request.getParameter("age"));

            // DEFENSE 2: Ignore user-supplied role - always assign default
            String role = "user"; // Never trust client-supplied roles

            // DEFENSE 3: Use parameterized queries
            try (Connection conn = DriverManager.getConnection(DB_URL, DB_USER, DB_PASS)) {
                String sql = "INSERT INTO users (username, email, age, role) VALUES (?, ?, ?, ?)";
                PreparedStatement stmt = conn.prepareStatement(sql);
                stmt.setString(1, username);
                stmt.setString(2, email.toLowerCase());
                stmt.setInt(3, age);
                stmt.setString(4, role);
                stmt.executeUpdate();

                logger.info("User registered: " + username);
                response.getWriter().write("User registered successfully");
            }
        } catch (ValidationException e) {
            logger.warning("Validation failed: " + e.getMessage());
            response.setStatus(400);
            response.getWriter().write("Invalid input: " + e.getMessage());
        } catch (Exception e) {
            logger.severe("Registration error: " + e.getMessage());
            response.setStatus(500);
            response.getWriter().write("Registration failed");
        }
    }

    private String validateUsername(String username) throws ValidationException {
        if (username == null || username.trim().isEmpty()) {
            throw new ValidationException("Username is required");
        }
        username = username.trim();
        if (!USERNAME_PATTERN.matcher(username).matches()) {
            throw new ValidationException("Username must be 3-20 alphanumeric characters");
        }
        return username;
    }

    private String validateEmail(String email) throws ValidationException {
        if (email == null || email.trim().isEmpty()) {
            throw new ValidationException("Email is required");
        }
        email = email.trim();
        if (!EMAIL_PATTERN.matcher(email).matches()) {
            throw new ValidationException("Invalid email format");
        }
        return email;
    }

    private int validateAge(String ageStr) throws ValidationException {
        if (ageStr == null || ageStr.trim().isEmpty()) {
            throw new ValidationException("Age is required");
        }
        try {
            int age = Integer.parseInt(ageStr.trim());
            if (age < MIN_AGE || age > MAX_AGE) {
                throw new ValidationException("Age must be between " + MIN_AGE + " and " + MAX_AGE);
            }
            return age;
        } catch (NumberFormatException e) {
            throw new ValidationException("Age must be a valid number");
        }
    }
}

class ValidationException extends Exception {
    public ValidationException(String message) {
        super(message);
    }
}
```

**Key Security Controls**:
- **Whitelist validation**: Username only allows alphanumeric characters and underscores via regex pattern
- **Business logic protection**: Age bounded to realistic range (13-120), role parameter completely ignored from client
- **Type-safe parsing**: Age parsed with proper exception handling to prevent crashes
- **Normalization**: Email converted to lowercase, all inputs trimmed before validation

Complex inputs like file uploads and nested JSON require multi-layer validation strategies. You need to validate not just format but also content type, size, structure, and business rules. This is where many applications fail - they validate the outer structure but miss nested attack vectors.

**PRODUCTION PATTERN**:

```java
import com.fasterxml.jackson.databind.*;
import com.fasterxml.jackson.databind.node.*;
import javax.servlet.http.*;
import javax.servlet.annotation.*;
import java.io.*;
import java.nio.file.*;
import java.security.*;
import java.util.*;
import java.util.logging.*;
import java.util.regex.*;

@MultipartConfig(
    maxFileSize = 5 * 1024 * 1024,      // 5MB per file
    maxRequestSize = 10 * 1024 * 1024,   // 10MB total
    fileSizeThreshold = 1024 * 1024      // 1MB before disk write
)
public class SecureDataIngestionServlet extends HttpServlet {

    private static final Logger logger = Logger.getLogger(SecureDataIngestionServlet.class.getName());
    private static final ObjectMapper objectMapper = new ObjectMapper();

    // Allowed file types with magic bytes validation
    private static final Map<String, byte[]> ALLOWED_FILE_SIGNATURES = Map.of(
        "application/pdf", new byte[]{0x25, 0x50, 0x44, 0x46},  // %PDF
        "image/png", new byte[]{(byte)0x89, 0x50, 0x4E, 0x47},  // PNG header
        "image/jpeg", new byte[]{(byte)0xFF, (byte)0xD8, (byte)0xFF}
    );

    private static final Set<String> ALLOWED_EXTENSIONS = Set.of("pdf", "png", "jpg", "jpeg");
    private static final int MAX_JSON_DEPTH = 5;
    private static final int MAX_ARRAY_SIZE = 100;
    private static final int MAX_STRING_LENGTH = 10000;

    @Override
    protected void doPost(HttpServletRequest request, HttpServletResponse response) 
            throws IOException {

        String contentType = request.getContentType();

        try {
            if (contentType != null && contentType.contains("multipart/form-data")) {
                handleFileUpload(request, response);
            } else if (contentType != null && contentType.contains("application/json")) {
                handleJsonPayload(request, response);
            } else {
                response.setStatus(415); // Unsupported Media Type
                response.getWriter().write("Unsupported content type");
            }
        } catch (ValidationException e) {
            logger.warning("Validation failed from " + request.getRemoteAddr() + ": " + e.getMessage());
            response.setStatus(400);
            response.getWriter().write(e.getMessage());
        } catch (Exception e) {
            logger.severe("Processing error: " + e.getMessage());
            response.setStatus(500);
            response.getWriter().write("Processing failed");
        }
    }

    // ==================== FILE UPLOAD VALIDATION ====================

    private void handleFileUpload(HttpServletRequest request, HttpServletResponse response) 
            throws Exception {

        Part filePart = request.getPart("file");
        if (filePart == null) {
            throw new ValidationException("No file provided");
        }

        // LAYER 1: Validate filename
        String filename = validateFilename(filePart.getSubmittedFileName());

        // LAYER 2: Validate extension
        String extension = getExtension(filename);
        if (!ALLOWED_EXTENSIONS.contains(extension.toLowerCase())) {
            throw new ValidationException("File type not allowed: " + extension);
        }

        // LAYER 3: Validate declared content type
        String declaredType = filePart.getContentType();
        if (!ALLOWED_FILE_SIGNATURES.containsKey(declaredType)) {
            throw new ValidationException("Content type not allowed: " + declaredType);
        }

        // LAYER 4: Validate actual file content (magic bytes)
        byte[] fileContent = filePart.getInputStream().readAllBytes();
        if (!validateMagicBytes(fileContent, declaredType)) {
            logger.warning("Magic bytes mismatch - possible file type spoofing");
            throw new ValidationException("File content does not match declared type");
        }

        // LAYER 5: Additional content scanning for PDFs
        if (declaredType.equals("application/pdf")) {
            validatePdfContent(fileContent);
        }

        // LAYER 6: Generate safe filename and store
        String safeFilename = generateSafeFilename(extension);
        Path uploadDir = Paths.get("/var/uploads").toAbsolutePath().normalize();
        Path targetPath = uploadDir.resolve(safeFilename).normalize();

        // Prevent path traversal
        if (!targetPath.startsWith(uploadDir)) {
            throw new ValidationException("Invalid file path");
        }

        Files.write(targetPath, fileContent);

        logger.info("File uploaded: " + safeFilename + " (" + fileContent.length + " bytes)");
        response.getWriter().write("File uploaded: " + safeFilename);
    }

    private String validateFilename(String filename) throws ValidationException {
        if (filename == null || filename.isEmpty()) {
            throw new ValidationException("Filename is required");
        }

        // Remove path components
        filename = Paths.get(filename).getFileName().toString();

        // Check for null bytes and path traversal
        if (filename.contains("\0") || filename.contains("..") || 
            filename.contains("/") || filename.contains("\\")) {
            throw new ValidationException("Invalid filename");
        }

        // Whitelist allowed characters
        if (!filename.matches("^[a-zA-Z0-9._-]{1,255}$")) {
            throw new ValidationException("Filename contains invalid characters");
        }

        return filename;
    }

    private boolean validateMagicBytes(byte[] content, String contentType) {
        byte[] expectedSignature = ALLOWED_FILE_SIGNATURES.get(contentType);
        if (expectedSignature == null || content.length < expectedSignature.length) {
            return false;
        }
        for (int i = 0; i < expectedSignature.length; i++) {
            if (content[i] != expectedSignature[i]) {
                return false;
            }
        }
        return true;
    }

    private void validatePdfContent(byte[] content) throws ValidationException {
        String pdfString = new String(content);
        // Check for JavaScript in PDF (common attack vector)
        if (pdfString.contains("/JavaScript") || pdfString.contains("/JS") ||
            pdfString.contains("/Launch") || pdfString.contains("/OpenAction")) {
            throw new ValidationException("PDF contains potentially malicious content");
        }
    }

    private String generateSafeFilename(String extension) {
        return UUID.randomUUID().toString() + "." + extension;
    }

    private String getExtension(String filename) {
        int lastDot = filename.lastIndexOf('.');
        return lastDot > 0 ? filename.substring(lastDot + 1) : "";
    }

    // ==================== JSON VALIDATION ====================

    private void handleJsonPayload(HttpServletRequest request, HttpServletResponse response) 
            throws Exception {

        // LAYER 1: Limit request body size
        String body = readLimitedBody(request, 100_000); // 100KB max

        // LAYER 2: Parse and validate structure
        JsonNode rootNode = objectMapper.readTree(body);
        validateJsonStructure(rootNode, 0);

        // LAYER 3: Validate business object
        UserProfileRequest profileRequest = validateUserProfileRequest(rootNode);

        logger.info("Valid JSON payload received for user: " + profileRequest.userId);
        response.getWriter().write("Profile updated successfully");
    }

    private String readLimitedBody(HttpServletRequest request, int maxSize) 
            throws IOException, ValidationException {

        StringBuilder body = new StringBuilder();
        try (BufferedReader reader = request.getReader()) {
            char[] buffer = new char[1024];
            int read;
            int totalRead = 0;
            while ((read = reader.read(buffer)) != -1) {
                totalRead += read;
                if (totalRead > maxSize) {
                    throw new ValidationException("Request body too large");
                }
                body.append(buffer, 0, read);
            }
        }
        return body.toString();
    }

    private void validateJsonStructure(JsonNode node, int depth) throws ValidationException {
        if (depth > MAX_JSON_DEPTH) {
            throw new ValidationException("JSON nesting too deep (max: " + MAX_JSON_DEPTH + ")");
        }

        if (node.isArray()) {
            ArrayNode array = (ArrayNode) node;
            if (array.size() > MAX_ARRAY_SIZE) {
                throw new ValidationException("Array too large (max: " + MAX_ARRAY_SIZE + ")");
            }
            for (JsonNode element : array) {
                validateJsonStructure(element, depth + 1);
            }
        } else if (node.isObject()) {
            ObjectNode obj = (ObjectNode) node;
            Iterator<Map.Entry<String, JsonNode>> fields = obj.fields();
            while (fields.hasNext()) {
                Map.Entry<String, JsonNode> field = fields.next();
                // Validate field names
                if (!field.getKey().matches("^[a-zA-Z_][a-zA-Z0-9_]{0,63}$")) {
                    throw new ValidationException("Invalid field name: " + field.getKey());
                }
                validateJsonStructure(field.getValue(), depth + 1);
            }
        } else if (node.isTextual()) {
            if (node.textValue().length() > MAX_STRING_LENGTH) {
                throw new ValidationException("String value too long (max: " + MAX_STRING_LENGTH + ")");
            }
        }
    }

    private UserProfileRequest validateUserProfileRequest(JsonNode root) throws ValidationException {
        UserProfileRequest req = new UserProfileRequest();

        // Validate required fields
        if (!root.has("userId") || !root.get("userId").isInt()) {
            throw new ValidationException("userId must be an integer");
        }
        req.userId = root.get("userId").intValue();
        if (req.userId <= 0) {
            throw new ValidationException("userId must be positive");
        }

        // Validate nested address object
        if (root.has("address")) {
            JsonNode address = root.get("address");
            if (!address.isObject()) {
                throw new ValidationException("address must be an object");
            }
            req.address = validateAddress(address);
        }

        // Validate preferences array
        if (root.has("preferences")) {
            JsonNode prefs = root.get("preferences");
            if (!prefs.isArray()) {
                throw new ValidationException("preferences must be an array");
            }
            req.preferences = validatePreferences((ArrayNode) prefs);
        }

        return req;
    }

    private Address validateAddress(JsonNode node) throws ValidationException {
        Address addr = new Address();

        if (node.has("street")) {
            String street = node.get("street").asText("");
            if (street.length() > 200 || !street.matches("^[a-zA-Z0-9\\s.,#-]*$")) {
                throw new ValidationException("Invalid street address");
            }
            addr.street = street;
        }

        if (node.has("zipCode")) {
            String zip = node.get("zipCode").asText("");
            if (!zip.matches("^[0-9]{5}(-[0-9]{4})?$")) {
                throw new ValidationException("Invalid ZIP code format");
            }
            addr.zipCode = zip;
        }

        return addr;
    }

    private List<String> validatePreferences(ArrayNode prefs) throws ValidationException {
        List<String> result = new ArrayList<>();
        Set<String> allowedPrefs = Set.of("email_notifications", "sms_alerts", "dark_mode", "two_factor");

        for (JsonNode pref : prefs) {
            if (!pref.isTextual()) {
                throw new ValidationException("Preferences must be strings");
            }
            String prefValue = pref.textValue();
            if (!allowedPrefs.contains(prefValue)) {
                throw new ValidationException("Unknown preference: " + prefValue);
            }
            result.add(prefValue);
        }
        return result;
    }

    // Data classes
    static class UserProfileRequest {
        int userId;
        Address address;
        List<String> preferences;
    }

    static class Address {
        String street;
        String zipCode;
    }
}
```

**Defense in Depth Layers**:

1. **Transport Layer**: Content-type validation, request size limits via @MultipartConfig
```java
@MultipartConfig(
    maxFileSize = 5 * 1024 * 1024,
    maxRequestSize = 10 * 1024 * 1024
)
```

2. **Structure Layer**: JSON depth limits, array size limits, field name validation
```java
if (depth > MAX_JSON_DEPTH) {
    throw new ValidationException("JSON nesting too deep");
}
if (array.size() > MAX_ARRAY_SIZE) {
    throw new ValidationException("Array too large");
}
```

3. **Content Layer**: Magic bytes validation, malicious content scanning, whitelist validation
```java
if (!validateMagicBytes(fileContent, declaredType)) {
    throw new ValidationException("File content does not match declared type");
}
if (pdfString.contains("/JavaScript")) {
    throw new ValidationException("PDF contains potentially malicious content");
}
```

4. **Business Logic Layer**: Type-specific validation, enumeration validation, range checks
```java
if (!allowedPrefs.contains(prefValue)) {
    throw new ValidationException("Unknown preference: " + prefValue);
}
```

**Additional Protections**:
- **Rate limiting**: Implement at API gateway level to prevent abuse
- **Antivirus scanning**: Integrate ClamAV or cloud scanning for uploaded files
- **Content Security Policy**: Return CSP headers when serving uploaded content
- **Audit logging**: Log all validation failures with IP addresses for threat detection
- **Schema validation**: Consider JSON Schema or Bean Validation (JSR-380) for complex objects
- **Quarantine storage**: Store uploads in isolated location until scanned and verified

