Complex structured input requires comprehensive validation at multiple layers. The 2023 Juniper Networks vulnerabilities (CVE-2023-36844 series) showed how missing validation on configuration parameters allowed remote code execution.

**PRODUCTION PATTERN**:

```go
package main

import (
	"context"
	"encoding/json"
	"fmt"
	"log"
	"net/http"
	"regexp"
	"strings"
	"time"
	"unicode/utf8"

	"github.com/go-playground/validator/v10"
	"golang.org/x/time/rate"
)

// Strict struct with validation tags
type UserProfileRequest struct {
	FirstName    string         `json:"first_name" validate:"required,min=1,max=50,alphaunicode"`
	LastName     string         `json:"last_name" validate:"required,min=1,max=50,alphaunicode"`
	Email        string         `json:"email" validate:"required,email,max=254"`
	Phone        string         `json:"phone" validate:"omitempty,e164"`
	DateOfBirth  string         `json:"date_of_birth" validate:"omitempty,datetime=2006-01-02"`
	Address      AddressRequest `json:"address" validate:"required"`
	Preferences  Preferences    `json:"preferences" validate:"omitempty"`
}

type AddressRequest struct {
	Street1    string `json:"street1" validate:"required,min=1,max=100"`
	Street2    string `json:"street2" validate:"omitempty,max=100"`
	City       string `json:"city" validate:"required,min=1,max=50,alphaunicode"`
	State      string `json:"state" validate:"required,len=2,alpha,uppercase"`
	PostalCode string `json:"postal_code" validate:"required,min=5,max=10"`
	Country    string `json:"country" validate:"required,iso3166_1_alpha2"`
}

type Preferences struct {
	Newsletter    bool     `json:"newsletter"`
	Notifications bool     `json:"notifications"`
	Language      string   `json:"language" validate:"omitempty,bcp47_language_tag"`
	Timezone      string   `json:"timezone" validate:"omitempty,timezone"`
	Tags          []string `json:"tags" validate:"omitempty,max=10,dive,min=1,max=30,alphanum"`
}

type ValidationError struct {
	Field   string `json:"field"`
	Message string `json:"message"`
}

type InputValidator struct {
	validator     *validator.Validate
	logger        *log.Logger
	rateLimiter   *rate.Limiter
	maxBodySize   int64
	dangerousPatterns []*regexp.Regexp
}

func NewInputValidator(logger *log.Logger) *InputValidator {
	v := validator.New()

	// Register custom validators
	v.RegisterValidation("no_sql_injection", noSQLInjection)
	v.RegisterValidation("no_xss", noXSS)
	v.RegisterValidation("safe_string", safeString)

	return &InputValidator{
		validator:   v,
		logger:      logger,
		rateLimiter: rate.NewLimiter(rate.Every(time.Second), 100),
		maxBodySize: 1 << 20, // 1MB
		dangerousPatterns: []*regexp.Regexp{
			regexp.MustCompile(`(?i)(union|select|insert|update|delete|drop|truncate|exec)\s`),
			regexp.MustCompile(`<script[^>]*>`),
			regexp.MustCompile(`javascript:`),
			regexp.MustCompile(`on\w+\s*=`),
		},
	}
}

func (iv *InputValidator) ValidateRequest(ctx context.Context, r *http.Request, dst interface{}) ([]ValidationError, error) {
	// Layer 1: Rate limiting
	if !iv.rateLimiter.Allow() {
		iv.logger.Printf("Rate limit exceeded from %s", r.RemoteAddr)
		return nil, fmt.Errorf("rate limit exceeded")
	}

	// Layer 2: Request size limit
	r.Body = http.MaxBytesReader(nil, r.Body, iv.maxBodySize)

	// Layer 3: Content-Type validation
	contentType := r.Header.Get("Content-Type")
	if !strings.HasPrefix(contentType, "application/json") {
		return nil, fmt.Errorf("invalid content type")
	}

	// Layer 4: JSON parsing with strict settings
	decoder := json.NewDecoder(r.Body)
	decoder.DisallowUnknownFields()

	if err := decoder.Decode(dst); err != nil {
		iv.logger.Printf("JSON decode error from %s: %v", r.RemoteAddr, err)
		return nil, fmt.Errorf("invalid JSON format")
	}

	// Layer 5: Struct validation
	err := iv.validator.StructCtx(ctx, dst)
	if err != nil {
		return iv.formatValidationErrors(err), nil
	}

	// Layer 6: Deep content inspection
	if errs := iv.deepContentInspection(dst); len(errs) > 0 {
		return errs, nil
	}

	return nil, nil
}

func (iv *InputValidator) formatValidationErrors(err error) []ValidationError {
	var errors []ValidationError
	for _, err := range err.(validator.ValidationErrors) {
		errors = append(errors, ValidationError{
			Field:   err.Field(),
			Message: fmt.Sprintf("validation failed on '%s' tag", err.Tag()),
		})
	}
	return errors
}

func (iv *InputValidator) deepContentInspection(data interface{}) []ValidationError {
	var errors []ValidationError

	// Convert to JSON and inspect all string values
	jsonBytes, _ := json.Marshal(data)
	var rawMap map[string]interface{}
	json.Unmarshal(jsonBytes, &rawMap)

	iv.inspectMap("", rawMap, &errors)
	return errors
}

func (iv *InputValidator) inspectMap(prefix string, m map[string]interface{}, errors *[]ValidationError) {
	for key, value := range m {
		fieldPath := key
		if prefix != "" {
			fieldPath = prefix + "." + key
		}

		switch v := value.(type) {
		case string:
			if err := iv.inspectString(fieldPath, v); err != nil {
				*errors = append(*errors, *err)
			}
		case map[string]interface{}:
			iv.inspectMap(fieldPath, v, errors)
		case []interface{}:
			for i, item := range v {
				if str, ok := item.(string); ok {
					if err := iv.inspectString(fmt.Sprintf("%s[%d]", fieldPath, i), str); err != nil {
						*errors = append(*errors, *err)
					}
				}
			}
		}
	}
}

func (iv *InputValidator) inspectString(field, value string) *ValidationError {
	// Check for invalid UTF-8
	if !utf8.ValidString(value) {
		return &ValidationError{Field: field, Message: "invalid UTF-8 encoding"}
	}

	// Check for null bytes
	if strings.Contains(value, "\x00") {
		iv.logger.Printf("Null byte injection attempt in field %s", field)
		return &ValidationError{Field: field, Message: "invalid characters"}
	}

	// Check for dangerous patterns
	for _, pattern := range iv.dangerousPatterns {
		if pattern.MatchString(value) {
			iv.logger.Printf("Dangerous pattern detected in field %s: %s", field, value)
			return &ValidationError{Field: field, Message: "potentially dangerous content"}
		}
	}

	return nil
}

// Custom validators
func noSQLInjection(fl validator.FieldLevel) bool {
	value := fl.Field().String()
	dangerousPatterns := []string{"'", "--", ";", "/*", "*/", "xp_"}
	for _, pattern := range dangerousPatterns {
		if strings.Contains(value, pattern) {
			return false
		}
	}
	return true
}

func noXSS(fl validator.FieldLevel) bool {
	value := fl.Field().String()
	dangerousPatterns := []string{"<script", "javascript:", "onerror", "onload"}
	lower := strings.ToLower(value)
	for _, pattern := range dangerousPatterns {
		if strings.Contains(lower, pattern) {
			return false
		}
	}
	return true
}

func safeString(fl validator.FieldLevel) bool {
	value := fl.Field().String()
	return utf8.ValidString(value) && !strings.Contains(value, "\x00")
}

// Production handler with full validation
func updateProfileHandler(iv *InputValidator) http.HandlerFunc {
	return func(w http.ResponseWriter, r *http.Request) {
		ctx, cancel := context.WithTimeout(r.Context(), 5*time.Second)
		defer cancel()

		var req UserProfileRequest
		validationErrors, err := iv.ValidateRequest(ctx, r, &req)

		if err != nil {
			w.Header().Set("Content-Type", "application/json")
			w.WriteHeader(http.StatusBadRequest)
			json.NewEncoder(w).Encode(map[string]string{"error": err.Error()})
			return
		}

		if len(validationErrors) > 0 {
			w.Header().Set("Content-Type", "application/json")
			w.WriteHeader(http.StatusUnprocessableEntity)
			json.NewEncoder(w).Encode(map[string]interface{}{"errors": validationErrors})
			return
		}

		// Sanitize before storage
		req.FirstName = strings.TrimSpace(req.FirstName)
		req.LastName = strings.TrimSpace(req.LastName)
		req.Email = strings.ToLower(strings.TrimSpace(req.Email))

		iv.logger.Printf("Profile update validated for: %s %s", req.FirstName, req.LastName)

		w.Header().Set("Content-Type", "application/json")
		w.WriteHeader(http.StatusOK)
		json.NewEncoder(w).Encode(map[string]string{"status": "profile updated"})
	}
}

func main() {
	logger := log.Default()
	iv := NewInputValidator(logger)

	mux := http.NewServeMux()
	mux.HandleFunc("/api/profile", updateProfileHandler(iv))

	server := &http.Server{
		Addr:         ":8080",
		Handler:      mux,
		ReadTimeout:  10 * time.Second,
		WriteTimeout: 10 * time.Second,
		IdleTimeout:  120 * time.Second,
	}

	log.Fatal(server.ListenAndServe())
}
```

