@dataclass
class FilterCondition:
    """Validated filter condition"""
    field: str
    operator: str
    value: Any

    def to_sql(self) -> tuple:
        """Convert to parameterized SQL fragment"""
        op_map = {
            'eq': '=', 'ne': '!=', 'gt': '>', 'lt': '<',
            'gte': '>=', 'lte': '<=', 'like': 'LIKE'
        }

        if self.operator == 'in':
            placeholders = ','.join(['?' for _ in self.value])
            return f"{self.field} IN ({placeholders})", list(self.value)
        elif self.operator == 'like':
            return f"{self.field} LIKE ?", [f"%{self.value}%"]
        else:
            return f"{self.field} {op_map[self.operator]} ?", [self.value]

@dataclass
class SearchRequest:
    """Validated search request with all parameters"""
    filters: List[FilterCondition] = field(default_factory=list)
    sort_field: str = 'created_at'
    sort_direction: str = 'desc'
    limit: int = 10
    offset: int = 0
    request_id: str = ''

