        if column not in allowed:
            raise ValueError(f"Invalid {context} column: {column}")
        return column

    @staticmethod
    def validate_operator(operator: str) -> str:
        """Validate filter operator against allowlist"""
        operator = operator.lower().strip()
        if operator not in ALLOWED_OPERATORS:
            raise ValueError(f"Invalid operator: {operator}")
        return operator

    @staticmethod
    def validate_value(field: str, operator: str, value: Any) -> Any:
        """Validate and sanitize filter value based on field type"""
        if value is None:
            raise ValueError(f"Value cannot be null for field: {field}")

        # Handle 'in' operator with list of values
        if operator == 'in':
            if not isinstance(value, list):
                raise ValueError("IN operator requires a list of values")
            if len(value) > MAX_IN_VALUES:
                raise ValueError(f"IN operator limited to {MAX_IN_VALUES} values")
            return [InputValidator.validate_single_value(field, v) for v in value]

        return InputValidator.validate_single_value(field, value)

    @staticmethod
    def validate_single_value(field: str, value: Any) -> Any:
        """Validate a single value based on field type"""
        if field == 'status':
            value = str(value).lower().strip()
            if value not in ALLOWED_STATUSES:
                raise ValueError(f"Invalid status value: {value}")
            return value

        if field in ('created_at', 'updated_at'):
            return InputValidator.validate_date(value)

        if field == 'id':
            try:
                return int(value)
            except (ValueError, TypeError):
                raise ValueError("ID must be an integer")

        if field in VALIDATION_PATTERNS:
            value = str(value).strip()
            if not VALIDATION_PATTERNS[field].match(value):
                raise ValueError(f"Invalid format for {field}")
            return value

        # Default string handling with length limit
        value = str(value).strip()[:200]
        return value

    @staticmethod
    def validate_date(value: str) -> str:
        """Validate and normalize date values"""
        try:
            if isinstance(value, str):
                dt = datetime.fromisoformat(value.replace('Z', '+00:00'))
            else:
                raise ValueError("Date must be ISO format string")

            # Prevent queries for dates too far in the past/future
            now = datetime.now(dt.tzinfo) if dt.tzinfo else datetime.now()
            max_past = now - timedelta(days=MAX_DATE_RANGE_DAYS * 10)
            max_future = now + timedelta(days=30)

            if dt < max_past or dt > max_future:
                raise ValueError("Date out of allowed range")

            return dt.isoformat()
        except Exception as e:
            raise ValueError(f"Invalid date format: {e}")

    @staticmethod
    def validate_pagination(limit: Any, offset: Any) -> tuple:
        """Validate pagination parameters"""
        try:
            limit = int(limit)
            offset = int(offset)
        except (ValueError, TypeError):
            raise ValueError("Limit and offset must be integers")

        if not 1 <= limit <= MAX_LIMIT:
            raise ValueError(f"Limit must be between 1 and {MAX_LIMIT}")
        if not 0 <= offset <= MAX_OFFSET:
            raise ValueError(f"Offset must be between 0 and {MAX_OFFSET}")

        return limit, offset

    @staticmethod
    def validate_sort(sort_field: str, sort_direction: str) -> tuple:
        """Validate sort parameters"""
        sort_field = InputValidator.validate_column(sort_field, 'sort')
        sort_direction = sort_direction.lower().strip()

        if sort_direction not in ALLOWED_SORT_DIRECTIONS:
            raise ValueError(f"Sort direction must be 'asc' or 'desc'")

        return sort_field, sort_direction

def parse_and_validate_request(request_data: dict) -> SearchRequest:
    """Parse and validate entire search request"""
    errors = []
    filters = []

    # Generate request ID for tracking
    request_id = hashlib.sha256(
        f"{datetime.utcnow().isoformat()}{json.dumps(request_data, sort_keys=True)}".encode()
    ).hexdigest()[:16]

    # Validate filters
    raw_filters = request_data.get('filters', [])
    if len(raw_filters) > MAX_FILTERS:
        errors.append(f"Maximum {MAX_FILTERS} filters allowed")
    else:
        for i, f in enumerate(raw_filters):
            try:
                field = InputValidator.validate_column(f.get('field', ''), 'filter')
                operator = InputValidator.validate_operator(f.get('operator', 'eq'))
                value = InputValidator.validate_value(field, operator, f.get('value'))
                filters.append(FilterCondition(field=field, operator=operator, value=value))
            except ValueError as e:
                errors.append(f"Filter {i}: {str(e)}")

    # Validate sort
    try:
        sort_field, sort_direction = InputValidator.validate_sort(
            request_data.get('sort_field', 'created_at'),
            request_data.get('sort_direction', 'desc')
        )
    except ValueError as e:
        errors.append(f"Sort: {str(e)}")
        sort_field, sort_direction = 'created_at', 'desc'

    # Validate pagination
    try:
        limit, offset = InputValidator.validate_pagination(
            request_data.get('limit', 10),
            request_data.get('offset', 0)
        )
    except ValueError as e:
        errors.append(f"Pagination: {str(e)}")
        limit, offset = 10, 0

    if errors:
        raise ValidationError(errors, request_id)

    return SearchRequest(
        filters=filters,
        sort_field=sort_field,
        sort_direction=sort_direction,
        limit=limit,
        offset=offset,
        request_id=request_id
    )

class ValidationError(Exception):
    def __init__(self, errors: List[str], request_id: str):
        self.errors = errors
        self.request_id = request_id

def require_auth(f):
    @wraps(f)
    def decorated(*args, **kwargs):
        auth_header = request.headers.get('Authorization', '')
        if not auth_header.startswith('Bearer '):
            audit_logger.warning(f"Missing auth token from {request.remote_addr}")
            abort(401)

        token = auth_header[7:]
        user = validate_and_decode_token(token)
        if not user:
            audit_logger.warning(f"Invalid auth token from {request.remote_addr}")
            abort(401)

        g.current_user = user
        return f(*args, **kwargs)
    return decorated

def validate_and_decode_token(token: str) -> Optional[dict]:
