```java
import javax.ws.rs.*;
import javax.ws.rs.core.MediaType;
import javax.ws.rs.core.Response;
import javax.validation.Valid;
import javax.validation.constraints.*;
import java.sql.*;
import java.util.regex.Pattern;
import org.owasp.encoder.Encode;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

@Path("/api/users")
public class UserRegistrationResource {

    private static final Logger logger = LoggerFactory.getLogger(UserRegistrationResource.class);
    private static final String DB_URL = "jdbc:postgresql://localhost/appdb";
    private static final String DB_USER = "dbuser";
    private static final String DB_PASS = "dbpassword";

    // Whitelist patterns for input validation
    private static final Pattern USERNAME_PATTERN = Pattern.compile("^[a-zA-Z0-9_]{3,30}$");
    private static final Pattern EMAIL_PATTERN = Pattern.compile("^[A-Za-z0-9+_.-]+@[A-Za-z0-9.-]+\\.[A-Za-z]{2,}$");
    private static final String[] ALLOWED_ROLES = {"USER", "VIEWER"};

    @POST
    @Path("/register")
    @Consumes(MediaType.APPLICATION_JSON)
    @Produces(MediaType.APPLICATION_JSON)
    public Response registerUser(@Valid UserDTO user) {

        // Layer 1: Validate all inputs before processing
        ValidationResult validation = validateUserInput(user);
        if (!validation.isValid()) {
            logger.warn("Invalid registration attempt: {}", validation.getErrors());
            return Response.status(Response.Status.BAD_REQUEST)
                .entity("{\"error\": \"" + Encode.forJava(validation.getErrors()) + "\"}")
                .build();
        }

        // Layer 2: Sanitize and normalize inputs
        String sanitizedUsername = Encode.forHtml(user.getUsername().trim().toLowerCase());
        String sanitizedEmail = user.getEmail().trim().toLowerCase();

        // Layer 3: Force role to default - never trust client-supplied role
        String safeRole = "USER";  // Server-controlled, ignore user input

        try (Connection conn = DriverManager.getConnection(DB_URL, DB_USER, DB_PASS)) {
            String sql = "INSERT INTO users (username, email, password_hash, age, role) VALUES (?, ?, ?, ?, ?)";
            PreparedStatement stmt = conn.prepareStatement(sql);
            stmt.setString(1, sanitizedUsername);
            stmt.setString(2, sanitizedEmail);
            stmt.setString(3, hashPassword(user.getPassword()));  // Hash password
            stmt.setInt(4, user.getAge());
            stmt.setString(5, safeRole);
            stmt.executeUpdate();

            logger.info("User registered successfully: {}", sanitizedUsername);
            return Response.ok("{\"status\": \"registered\"}").build();

        } catch (SQLException e) {
            logger.error("Database error during registration", e);
            return Response.serverError().entity("{\"error\": \"Registration failed\"}").build();
        }
    }

    private ValidationResult validateUserInput(UserDTO user) {
        StringBuilder errors = new StringBuilder();

        // Username: alphanumeric, 3-30 chars
        if (user.getUsername() == null || !USERNAME_PATTERN.matcher(user.getUsername()).matches()) {
            errors.append("Invalid username format. ");
        }

        // Email: valid format
        if (user.getEmail() == null || !EMAIL_PATTERN.matcher(user.getEmail()).matches()) {
            errors.append("Invalid email format. ");
        }

        // Password: minimum strength requirements
        if (user.getPassword() == null || user.getPassword().length() < 12 ||
            !user.getPassword().matches(".*[A-Z].*") ||
            !user.getPassword().matches(".*[a-z].*") ||
            !user.getPassword().matches(".*[0-9].*")) {
            errors.append("Password must be 12+ chars with uppercase, lowercase, and numbers. ");
        }

        // Age: reasonable bounds
        if (user.getAge() < 13 || user.getAge() > 120) {
            errors.append("Age must be between 13 and 120. ");
        }

        return new ValidationResult(errors.length() == 0, errors.toString());
    }

    private String hashPassword(String password) {
        // Use BCrypt or Argon2 in production
        return org.mindrot.jbcrypt.BCrypt.hashpw(password, org.mindrot.jbcrypt.BCrypt.gensalt(12));
    }
}
```

**Key Security Controls**:
- **Whitelist Validation**: Regex patterns define exactly what's allowed, rejecting everything else
- **Server-Controlled Roles**: Role is set server-side, never trusting client input for authorization
- **Input Sanitization**: OWASP Encoder prevents XSS when data is displayed
- **Password Hashing**: Passwords never stored in plaintext
- **Secure Error Handling**: Detailed errors logged server-side, generic errors returned to client

Complex nested objects require deep validation at every level. Attackers often exploit nested structures to bypass surface-level validation. The 2024 Spring4Shell vulnerability (CVE-2022-22965) showed how nested property binding without validation leads to RCE.

**PRODUCTION PATTERN**:

```java
import javax.validation.Valid;
import javax.validation.constraints.*;
import javax.ws.rs.*;
import javax.ws.rs.core.MediaType;
import javax.ws.rs.core.Response;
import java.math.BigDecimal;
import java.util.List;
import java.util.Set;
import java.util.stream.Collectors;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

@Path("/api/orders")
public class OrderResource {

    private static final Logger logger = LoggerFactory.getLogger(OrderResource.class);
    private static final int MAX_ITEMS_PER_ORDER = 100;
    private static final int MAX_CUSTOM_OPTIONS = 10;
    private static final BigDecimal MAX_ORDER_TOTAL = new BigDecimal("100000.00");

    // Whitelist of valid product IDs (in production, verify against database)
    private final ProductService productService;
    private final RateLimiter rateLimiter;
    private final AuditLogger auditLogger;

    public OrderResource(ProductService productService, RateLimiter rateLimiter, AuditLogger auditLogger) {
        this.productService = productService;
        this.rateLimiter = rateLimiter;
        this.auditLogger = auditLogger;
    }

    @POST
    @Path("/submit")
    @Consumes(MediaType.APPLICATION_JSON)
    @Produces(MediaType.APPLICATION_JSON)
    public Response submitOrder(@Valid OrderRequestDTO order, @HeaderParam("X-Request-ID") String requestId) {

        String correlationId = requestId != null ? requestId : java.util.UUID.randomUUID().toString();

        // Layer 1: Rate limiting per user
        if (!rateLimiter.tryAcquire(order.getUserId())) {
            logger.warn("Rate limit exceeded for user: {} [correlationId={}]", order.getUserId(), correlationId);
            return Response.status(429).entity("{\"error\": \"Too many requests\"}").build();
        }

        // Layer 2: Structural validation
        StructuralValidationResult structuralResult = validateStructure(order);
        if (!structuralResult.isValid()) {
            auditLogger.logSecurityEvent("INVALID_ORDER_STRUCTURE", order.getUserId(), structuralResult.getErrors());
            return Response.status(400).entity("{\"error\": \"" + structuralResult.getErrors() + "\"}").build();
        }

        // Layer 3: Business logic validation
        BusinessValidationResult businessResult = validateBusinessRules(order);
        if (!businessResult.isValid()) {
            auditLogger.logSecurityEvent("BUSINESS_RULE_VIOLATION", order.getUserId(), businessResult.getErrors());
            return Response.status(400).entity("{\"error\": \"" + businessResult.getErrors() + "\"}").build();
        }

        // Layer 4: Server-side price calculation (NEVER trust client prices)
        OrderCalculation serverCalculation = calculateOrderTotal(order);
        if (!serverCalculation.matchesClientTotal(order.getClientTotal())) {
            logger.warn("Price manipulation detected: client={}, server={} [userId={}, correlationId={}]",
                order.getClientTotal(), serverCalculation.getTotal(), order.getUserId(), correlationId);
            auditLogger.logSecurityEvent("PRICE_MANIPULATION_ATTEMPT", order.getUserId(), 
                "Client: " + order.getClientTotal() + ", Server: " + serverCalculation.getTotal());
            return Response.status(400).entity("{\"error\": \"Price verification failed\"}").build();
        }

        // Layer 5: Process order with validated, sanitized data
        try {
            Order processedOrder = orderService.processOrder(
                order.getUserId(),
                serverCalculation.getSanitizedItems(),
                serverCalculation.getTotal()
            );

            auditLogger.logOrderSubmission(processedOrder.getId(), order.getUserId(), serverCalculation.getTotal());
            logger.info("Order submitted successfully: orderId={}, userId={}, total={} [correlationId={}]",
                processedOrder.getId(), order.getUserId(), serverCalculation.getTotal(), correlationId);

            return Response.ok("{\"orderId\": \"" + processedOrder.getId() + "\", \"total\": " + serverCalculation.getTotal() + "}").build();

        } catch (Exception e) {
            logger.error("Order processing failed [correlationId={}]", correlationId, e);
            return Response.serverError().entity("{\"error\": \"Order processing failed\"}").build();
        }
    }

    private StructuralValidationResult validateStructure(OrderRequestDTO order) {
        StringBuilder errors = new StringBuilder();

        // Validate userId format
        if (order.getUserId() == null || !order.getUserId().matches("^[a-f0-9\\-]{36}$")) {
            errors.append("Invalid user ID format. ");
        }

        // Validate items collection size (prevent DoS)
        if (order.getItems() == null || order.getItems().isEmpty()) {
            errors.append("Order must contain at least one item. ");
        } else if (order.getItems().size() > MAX_ITEMS_PER_ORDER) {
            errors.append("Order exceeds maximum item limit of " + MAX_ITEMS_PER_ORDER + ". ");
        }

        // Deep validation of each item
        if (order.getItems() != null) {
            for (int i = 0; i < order.getItems().size(); i++) {
                OrderItemDTO item = order.getItems().get(i);
                String itemErrors = validateOrderItem(item, i);
                errors.append(itemErrors);
            }
        }

        return new StructuralValidationResult(errors.length() == 0, errors.toString());
    }

    private String validateOrderItem(OrderItemDTO item, int index) {
        StringBuilder errors = new StringBuilder();
        String prefix = "Item[" + index + "]: ";

        // Product ID validation
        if (item.getProductId() == null || !item.getProductId().matches("^PROD-[A-Z0-9]{8}$")) {
            errors.append(prefix).append("Invalid product ID format. ");
        }

        // Quantity bounds
        if (item.getQuantity() == null || item.getQuantity() < 1 || item.getQuantity() > 9999) {
            errors.append(prefix).append("Quantity must be between 1 and 9999. ");
        }

        // Custom options validation
        if (item.getCustomOptions() != null) {
            if (item.getCustomOptions().size() > MAX_CUSTOM_OPTIONS) {
                errors.append(prefix).append("Too many custom options. ");
            }
            for (CustomOptionDTO option : item.getCustomOptions()) {
                errors.append(validateCustomOption(option, index));
            }
        }

        return errors.toString();
    }

    private String validateCustomOption(CustomOptionDTO option, int itemIndex) {
        StringBuilder errors = new StringBuilder();

        // Option key: whitelist of allowed options
        Set<String> allowedKeys = Set.of("size", "color", "engraving", "gift_wrap");
        if (option.getKey() == null || !allowedKeys.contains(option.getKey().toLowerCase())) {
            errors.append("Item[").append(itemIndex).append("]: Invalid custom option key. ");
        }

        // Option value: bounded length, alphanumeric with limited special chars
        if (option.getValue() == null || option.getValue().length() > 100 ||
            !option.getValue().matches("^[a-zA-Z0-9 \\-_.,!?]{1,100}$")) {
            errors.append("Item[").append(itemIndex).append("]: Invalid custom option value. ");
        }

        return errors.toString();
    }

    private BusinessValidationResult validateBusinessRules(OrderRequestDTO order) {
        StringBuilder errors = new StringBuilder();

        // Verify all products exist and are available
        for (OrderItemDTO item : order.getItems()) {
            Product product = productService.findById(item.getProductId());
            if (product == null) {
                errors.append("Product not found: ").append(item.getProductId()).append(". ");
            } else if (!product.isAvailable()) {
                errors.append("Product not available: ").append(item.getProductId()).append(". ");
            } else if (item.getQuantity() > product.getStockQuantity()) {
                errors.append("Insufficient stock for: ").append(item.getProductId()).append(". ");
            }
        }

        return new BusinessValidationResult(errors.length() == 0, errors.toString());
    }

    private OrderCalculation calculateOrderTotal(OrderRequestDTO order) {
        // CRITICAL: Calculate prices server-side from authoritative source
        BigDecimal total = BigDecimal.ZERO;
        List<SanitizedOrderItem> sanitizedItems = new java.util.ArrayList<>();

        for (OrderItemDTO item : order.getItems()) {
            Product product = productService.findById(item.getProductId());
            BigDecimal itemTotal = product.getPrice().multiply(BigDecimal.valueOf(item.getQuantity()));

            // Apply custom option pricing from server-side rules
            if (item.getCustomOptions() != null) {
                for (CustomOptionDTO option : item.getCustomOptions()) {
                    BigDecimal optionPrice = productService.getOptionPrice(item.getProductId(), option.getKey(), option.getValue());
                    itemTotal = itemTotal.add(optionPrice.multiply(BigDecimal.valueOf(item.getQuantity())));
                }
            }

            total = total.add(itemTotal);
            sanitizedItems.add(new SanitizedOrderItem(item.getProductId(), item.getQuantity(), itemTotal));
        }

        // Enforce maximum order total
        if (total.compareTo(MAX_ORDER_TOTAL) > 0) {
            throw new BusinessRuleViolationException("Order total exceeds maximum allowed");
        }

        return new OrderCalculation(total, sanitizedItems);
    }
}

