type UserProfile struct {
	ID       int    `json:"id"`
	Username string `json:"username"`
	Email    string `json:"email"`
	Age      int    `json:"age"`
	Bio      string `json:"bio"`
	Website  string `json:"website"`
}

type ValidationError struct {
	Field   string `json:"field"`
	Message string `json:"message"`
}

var (
	db              *sql.DB
	usernamePattern = regexp.MustCompile(`^[a-zA-Z0-9_]{3,30}$`)
)

func validateProfile(p *UserProfile) []ValidationError {
	var errors []ValidationError

	// Username validation: alphanumeric and underscore only, 3-30 chars
	if !usernamePattern.MatchString(p.Username) {
		errors = append(errors, ValidationError{
			Field:   "username",
			Message: "Username must be 3-30 alphanumeric characters or underscores",
		})
	}

	// Email validation using standard library
	if _, err := mail.ParseAddress(p.Email); err != nil {
		errors = append(errors, ValidationError{
			Field:   "email",
			Message: "Invalid email address format",
		})
	}

	// Age validation: reasonable bounds
	if p.Age < 13 || p.Age > 120 {
		errors = append(errors, ValidationError{
			Field:   "age",
			Message: "Age must be between 13 and 120",
		})
	}

	// Bio validation: length and content
	if utf8.RuneCountInString(p.Bio) > 500 {
		errors = append(errors, ValidationError{
			Field:   "bio",
			Message: "Bio must not exceed 500 characters",
		})
	}

	// Website validation: must be valid HTTPS URL
	if p.Website != "" {
		parsedURL, err := url.Parse(p.Website)
		if err != nil || (parsedURL.Scheme != "https" && parsedURL.Scheme != "http") {
			errors = append(errors, ValidationError{
				Field:   "website",
				Message: "Website must be a valid HTTP/HTTPS URL",
			})
		}
	}

	return errors
}

func sanitizeHTML(input string) string {
	// Remove potential XSS vectors
	replacer := strings.NewReplacer(
		"<", "&lt;",
		">", "&gt;",
		"&", "&amp;",
		"\"", "&quot;",
		"'", "&#39;",
	)
	return replacer.Replace(input)
}

func updateProfileSecure(w http.ResponseWriter, r *http.Request) {
	var profile UserProfile

	// Limit request body size
	r.Body = http.MaxBytesReader(w, r.Body, 1024*10) // 10KB max

	if err := json.NewDecoder(r.Body).Decode(&profile); err != nil {
		http.Error(w, "Invalid JSON", http.StatusBadRequest)
		return
	}

	// Validate all input
	if errors := validateProfile(&profile); len(errors) > 0 {
		w.WriteHeader(http.StatusBadRequest)
		json.NewEncoder(w).Encode(map[string]interface{}{"errors": errors})
		return
	}

	// Sanitize text fields for XSS prevention
	profile.Bio = sanitizeHTML(profile.Bio)

	// Use parameterized query - Role is NOT updateable by users
	query := `UPDATE users SET username=$1, email=$2, age=$3, bio=$4, website=$5 
	          WHERE id=$6`

	_, err := db.Exec(query,
		profile.Username,
		profile.Email,
		profile.Age,
		profile.Bio,
		profile.Website,
		profile.ID,
	)
	if err != nil {
		log.Printf("Database error updating profile %d: %v", profile.ID, err)
		http.Error(w, "Internal server error", http.StatusInternalServerError)
		return
	}

	w.WriteHeader(http.StatusOK)
	json.NewEncoder(w).Encode(map[string]string{"status": "updated"})
}
