// File upload validation
type FileValidationResult struct {
	Valid       bool
	FileName    string
	ContentType string
	Size        int64
	Checksum    string
	Errors      []string
}

func init() {
	validate = validator.New()

	// Register custom validation for safe strings
	validate.RegisterValidation("safepath", validateSafePath)
	validate.RegisterValidation("noscript", validateNoScript)
}

// Custom validator: prevent path traversal
func validateSafePath(fl validator.FieldLevel) bool {
	path := fl.Field().String()
	if strings.Contains(path, "..") || strings.Contains(path, "//") {
		return false
	}
	cleanPath := filepath.Clean(path)
	return cleanPath == path && !filepath.IsAbs(path)
}

// Custom validator: prevent script injection
func validateNoScript(fl validator.FieldLevel) bool {
	value := strings.ToLower(fl.Field().String())
	dangerousPatterns := []string{
		"<script", "javascript:", "onerror=", "onload=",
		"onclick=", "onmouseover=", "onfocus=", "onblur=",
	}
	for _, pattern := range dangerousPatterns {
		if strings.Contains(value, pattern) {
			return false
		}
	}
	return true
}

// Validate file upload with comprehensive checks
func ValidateFileUpload(file multipart.File, header *multipart.FileHeader) FileValidationResult {
	result := FileValidationResult{
		Valid:    true,
		FileName: header.Filename,
		Size:     header.Size,
		Errors:   []string{},
	}

	// 1. File size validation
	if header.Size > config.MaxFileSize {
		result.Valid = false
		result.Errors = append(result.Errors, 
			fmt.Sprintf("File size %d exceeds maximum %d bytes", header.Size, config.MaxFileSize))
	}

	// 2. Filename validation - prevent path traversal
	cleanName := filepath.Base(header.Filename)
	if cleanName != header.Filename || strings.Contains(header.Filename, "..") {
		result.Valid = false
		result.Errors = append(result.Errors, "Invalid filename detected")
		return result
	}

	// 3. File extension validation
	ext := strings.ToLower(filepath.Ext(header.Filename))
	if !config.AllowedFileTypes[ext] {
		result.Valid = false
		result.Errors = append(result.Errors,
			fmt.Sprintf("File type %s not allowed", ext))
	}

	// 4. Magic bytes validation - verify actual file type
	buf := make([]byte, 512)
	n, err := file.Read(buf)
	if err != nil && err != io.EOF {
		result.Valid = false
		result.Errors = append(result.Errors, "Failed to read file content")
		return result
	}

	// Reset file pointer
	file.Seek(0, io.SeekStart)

	detectedType := http.DetectContentType(buf[:n])
	result.ContentType = detectedType

	// Validate content type matches extension
	if !isContentTypeAllowed(detectedType, ext) {
		result.Valid = false
		result.Errors = append(result.Errors,
			fmt.Sprintf("Content type %s doesn't match extension %s", detectedType, ext))
	}

	// 5. Calculate checksum for integrity verification
	hash := sha256.New()
	if _, err := io.Copy(hash, file); err == nil {
		result.Checksum = hex.EncodeToString(hash.Sum(nil))
	}
	file.Seek(0, io.SeekStart)

	return result
}

func isContentTypeAllowed(contentType, ext string) bool {
	allowedTypes := map[string][]string{
		".pdf":  {"application/pdf"},
		".png":  {"image/png"},
		".jpg":  {"image/jpeg"},
		".jpeg": {"image/jpeg"},
		".doc":  {"application/msword"},
		".docx": {"application/vnd.openxmlformats-officedocument.wordprocessingml.document", "application/zip"},
	}

	allowed, exists := allowedTypes[ext]
	if !exists {
		return false
	}

	for _, t := range allowed {
		if strings.HasPrefix(contentType, t) {
			return true
		}
	}
	return false
}

// Validate nested JSON with depth checking
func ValidateJSONDepth(data []byte, maxDepth int) error {
	decoder := json.NewDecoder(bytes.NewReader(data))
	depth := 0

	for {
		token, err := decoder.Token()
		if err == io.EOF {
			return nil
		}
		if err != nil {
			return fmt.Errorf("JSON parse error: %w", err)
		}

		switch token {
		case json.Delim('['), json.Delim('{'):
			depth++
			if depth > maxDepth {
				return fmt.Errorf("JSON nesting depth %d exceeds maximum %d", depth, maxDepth)
			}
		case json.Delim(']'), json.Delim('}'):
			depth--
		}
	}
}

// Production handler with comprehensive validation
func HandleOrderWithValidation(w http.ResponseWriter, r *http.Request) {
	// 1. Request timeout
	ctx, cancel := context.WithTimeout(r.Context(), config.RequestTimeout)
	defer cancel()
	r = r.WithContext(ctx)

	// 2. Limit request body size
	r.Body = http.MaxBytesReader(w, r.Body, 1024*1024) // 1MB max

	// 3. Read body for multiple validations
	body, err := io.ReadAll(r.Body)
	if err != nil {
		log.Printf("ERROR: Failed to read request body: %v", err)
		http.Error(w, "Request body too large", http.StatusRequestEntityTooLarge)
		return
	}

	// 4. Validate JSON depth before parsing
	if err := ValidateJSONDepth(body, config.MaxNestingDepth); err != nil {
		log.Printf("SECURITY: JSON depth violation from %s: %v", r.RemoteAddr, err)
		http.Error(w, "Invalid request structure", http.StatusBadRequest)
		return
	}

	// 5. Parse JSON into struct
	var order OrderRequest
	if err := json.Unmarshal(body, &order); err != nil {
		log.Printf("ERROR: JSON unmarshal failed: %v", err)
		http.Error(w, "Invalid JSON format", http.StatusBadRequest)
		return
	}

	// 6. Validate with struct tags
	if err := validate.Struct(order); err != nil {
		var validationErrors []map[string]string
		for _, err := range err.(validator.ValidationErrors) {
			validationErrors = append(validationErrors, map[string]string{
				"field":   err.Field(),
				"tag":     err.Tag(),
				"message": getValidationMessage(err),
			})
		}
		log.Printf("VALIDATION: Request from %s failed validation: %v", r.RemoteAddr, validationErrors)
		w.WriteHeader(http.StatusBadRequest)
		json.NewEncoder(w).Encode(map[string]interface{}{"errors": validationErrors})
		return
	}

	// 7. Additional business logic validation
	if err := validateBusinessRules(&order); err != nil {
		log.Printf("BUSINESS: Order validation failed: %v", err)
		http.Error(w, err.Error(), http.StatusUnprocessableEntity)
		return
	}

	// 8. Audit logging for successful validation
	log.Printf("AUDIT: Order received from customer %s with %d items", 
		order.CustomerID, len(order.Items))

	w.WriteHeader(http.StatusAccepted)
	json.NewEncoder(w).Encode(map[string]string{"status": "accepted"})
}

func getValidationMessage(err validator.FieldError) string {
	switch err.Tag() {
	case "required":
		return fmt.Sprintf("%s is required", err.Field())
	case "min":
		return fmt.Sprintf("%s must be at least %s", err.Field(), err.Param())
	case "max":
		return fmt.Sprintf("%s must not exceed %s", err.Field(), err.Param())
	default:
		return fmt.Sprintf("%s failed %s validation", err.Field(), err.Tag())
	}
}

func validateBusinessRules(order *OrderRequest) error {
	// Calculate total to prevent price manipulation
	var total float64
	for _, item := range order.Items {
		total += item.Price * float64(item.Quantity)
	}

	if total > 1000000 {
		return errors.New("order total exceeds maximum allowed value")
	}

	return nil
}
