For production applications with complex validation needs, you should use a schema-based validation library like Pydantic or Marshmallow. These provide declarative validation, automatic type coercion, nested object support, and better error messages.

**PRODUCTION PATTERN**:

```python
from flask import Flask, request, jsonify
from pydantic import BaseModel, Field, EmailStr, validator, root_validator
from pydantic import ValidationError as PydanticValidationError
from typing import Optional, List
from enum import Enum
from functools import wraps
import logging
import hashlib
import time
from datetime import datetime

app = Flask(__name__)
logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)

# Rate limiting storage (use Redis in production)
request_counts = {}

class UserRole(str, Enum):
    USER = "user"
    GUEST = "guest"
    # ADMIN role never exposed to client input

class AddressSchema(BaseModel):
    """Nested object validation for address."""
    street: str = Field(..., min_length=5, max_length=200)
    city: str = Field(..., min_length=2, max_length=100)
    postal_code: str = Field(..., regex=r'^[A-Z0-9]{3,10}$')
    country: str = Field(..., min_length=2, max_length=2)  # ISO country code

    @validator('street', 'city')
    def sanitize_text(cls, v):
        # Remove potential XSS/injection characters
        dangerous_chars = '<>"\'{};'
        return ''.join(c for c in v if c not in dangerous_chars).strip()

class ProductSchema(BaseModel):
    """Array item validation for order products."""
    product_id: str = Field(..., regex=r'^[A-Z0-9]{8,12}$')
    quantity: int = Field(..., ge=1, le=100)

    @validator('quantity')
    def validate_quantity(cls, v):
        if v <= 0:
            raise ValueError('Quantity must be positive')
        return v

class UserRegistrationSchema(BaseModel):
    """Complete user registration with nested validation."""
    username: str = Field(..., min_length=3, max_length=30, regex=r'^[a-zA-Z0-9_]+$')
    email: EmailStr
    password: str = Field(..., min_length=12, max_length=128)
    age: Optional[int] = Field(None, ge=13, le=120)
    addresses: Optional[List[AddressSchema]] = Field(default=[], max_items=5)
    preferences: Optional[dict] = Field(default={})

    @validator('password')
    def validate_password_strength(cls, v):
        if not any(c.isupper() for c in v):
            raise ValueError('Password must contain uppercase letter')
        if not any(c.islower() for c in v):
            raise ValueError('Password must contain lowercase letter')
        if not any(c.isdigit() for c in v):
            raise ValueError('Password must contain digit')
        if not any(c in '!@#$%^&*()_+-=' for c in v):
            raise ValueError('Password must contain special character')
        return v

    @validator('preferences')
    def validate_preferences(cls, v):
        # Limit preference keys and values
        allowed_keys = {'theme', 'language', 'notifications', 'timezone'}
        if not all(k in allowed_keys for k in v.keys()):
            raise ValueError(f'Preferences must only contain: {allowed_keys}')
        # Limit value sizes to prevent DoS
        for key, value in v.items():
            if isinstance(value, str) and len(value) > 50:
                raise ValueError(f'Preference value too long: {key}')
        return v

    class Config:
        # Reject extra fields not in schema
        extra = 'forbid'
        # Strip whitespace from strings
        anystr_strip_whitespace = True

class OrderSchema(BaseModel):
    """Order with array of products."""
    customer_id: str = Field(..., regex=r'^CUST[0-9]{10}$')
    products: List[ProductSchema] = Field(..., min_items=1, max_items=50)
    shipping_address: AddressSchema
    express_shipping: bool = False
    notes: Optional[str] = Field(None, max_length=500)

    @root_validator
    def validate_order_totals(cls, values):
        products = values.get('products', [])
        total_items = sum(p.quantity for p in products)
        if total_items > 200:
            raise ValueError('Order cannot exceed 200 total items')
        return values

def validate_schema(schema_class):
    """Decorator for automatic schema validation."""
    def decorator(f):
        @wraps(f)
        def wrapped(*args, **kwargs):
            try:
                data = request.get_json()
                if data is None:
                    return jsonify({"error": "Request body must be JSON"}), 400

                # Validate against schema
                validated = schema_class(**data)
                # Pass validated model to handler
                kwargs['validated_data'] = validated
                return f(*args, **kwargs)

            except PydanticValidationError as e:
                # Log validation failures for security monitoring
                logger.warning(
                    f"Validation failed from {request.remote_addr}: "
                    f"{e.error_count()} errors"
                )
                # Return structured errors (safe, no internal details)
                errors = [
                    {"field": '.'.join(str(x) for x in err['loc']), 
                     "message": err['msg']}
                    for err in e.errors()
                ]
                return jsonify({"errors": errors}), 400

        return wrapped
    return decorator

def rate_limit(max_requests=10, window_seconds=60):
    """Simple rate limiting decorator."""
    def decorator(f):
        @wraps(f)
        def wrapped(*args, **kwargs):
            client_ip = request.remote_addr
            current_time = time.time()

            # Clean old entries
            if client_ip in request_counts:
                request_counts[client_ip] = [
                    t for t in request_counts[client_ip]
                    if current_time - t < window_seconds
                ]
            else:
                request_counts[client_ip] = []

            if len(request_counts[client_ip]) >= max_requests:
                logger.warning(f"Rate limit exceeded: {client_ip}")
                return jsonify({"error": "Rate limit exceeded"}), 429

            request_counts[client_ip].append(current_time)
            return f(*args, **kwargs)
        return wrapped
    return decorator

@app.route('/api/register', methods=['POST'])
