  // Directly using user input without validation
  const transfer = {
    from: fromAccount,
    to: toAccount,
    amount: amount,
    currency: currency,
    timestamp: new Date()
  };

  // Process transfer with unvalidated data
  await processTransfer(transfer);

  res.json({ success: true, transfer });
});

app.post('/api/user/profile', async (req, res) => {
