**SECURE VERSION**:

```javascript
const express = require('express');
const { body, validationResult } = require('express-validator');
const validator = require('validator');

const app = express();
app.use(express.json({ limit: '10kb' })); // Limit payload size

// Allowlist of permitted fields for each endpoint
const ALLOWED_TRANSFER_FIELDS = ['fromAccount', 'toAccount', 'amount', 'currency'];
const ALLOWED_CURRENCIES = ['USD', 'EUR', 'GBP', 'JPY'];
const MAX_TRANSFER_AMOUNT = 100000;
const MIN_TRANSFER_AMOUNT = 0.01;

// Input sanitization middleware
const sanitizeInput = (allowedFields) => (req, res, next) => {
  const sanitized = {};
  for (const field of allowedFields) {
    if (req.body[field] !== undefined) {
      sanitized[field] = req.body[field];
    }
  }
  req.body = sanitized;
  next();
};

// SECURE: Comprehensive input validation
app.post('/api/transfer',
  sanitizeInput(ALLOWED_TRANSFER_FIELDS),
  [
    body('fromAccount')
      .isString()
      .matches(/^[A-Z0-9]{10,20}$/)
      .withMessage('Invalid account format'),
    body('toAccount')
      .isString()
      .matches(/^[A-Z0-9]{10,20}$/)
      .withMessage('Invalid account format'),
    body('amount')
      .isFloat({ min: MIN_TRANSFER_AMOUNT, max: MAX_TRANSFER_AMOUNT })
      .withMessage(`Amount must be between ${MIN_TRANSFER_AMOUNT} and ${MAX_TRANSFER_AMOUNT}`),
    body('currency')
      .isIn(ALLOWED_CURRENCIES)
      .withMessage('Invalid currency')
  ],
  async (req, res) => {
    const errors = validationResult(req);
    if (!errors.isEmpty()) {
      return res.status(400).json({ errors: errors.array() });
    }

    const { fromAccount, toAccount, amount, currency } = req.body;

    // Additional business logic validation
    if (fromAccount === toAccount) {
      return res.status(400).json({ error: 'Cannot transfer to same account' });
    }

    // Verify user owns fromAccount (authorization check)
    const userOwnsAccount = await verifyAccountOwnership(req.user.id, fromAccount);
    if (!userOwnsAccount) {
      return res.status(403).json({ error: 'Unauthorized account access' });
    }

    const transfer = {
      from: fromAccount,
      to: toAccount,
      amount: parseFloat(amount.toFixed(2)), // Normalize precision
      currency: currency,
      timestamp: new Date(),
      initiatedBy: req.user.id
    };

    await processTransfer(transfer);
    res.json({ success: true, transferId: transfer.id });
  }
);

app.listen(3000);
```

**Key Security Controls**:
- **Allowlist validation**: Only permitted fields are processed, blocking mass assignment
- **Type validation**: Each field validated for correct data type
- **Range validation**: Numerical bounds prevent negative/excessive amounts
- **Format validation**: Regex patterns ensure account numbers match expected format
- **Enum validation**: Currency must be from predefined list
- **Authorization check**: Verify user owns the source account

Nested object validation is more complex and is where many applications fail. Attackers exploit deeply nested structures for prototype pollution, resource exhaustion, and bypassing shallow validation. Here's a production-ready approach.

**PRODUCTION PATTERN**:

```javascript
const express = require('express');
const { body, validationResult, checkSchema } = require('express-validator');
const Ajv = require('ajv');
const addFormats = require('ajv-formats');

const app = express();

// Defense Layer 1: Limit parsing depth and size
app.use(express.json({
  limit: '50kb',
  strict: true,
  reviver: (key, value) => {
    // Prevent prototype pollution
    if (key === '__proto__' || key === 'constructor' || key === 'prototype') {
      throw new Error('Invalid property name');
    }
    return value;
  }
}));

// Defense Layer 2: JSON Schema validation with AJV
const ajv = new Ajv({
  allErrors: true,
  removeAdditional: true,  // Strip unknown properties
  useDefaults: true,
  coerceTypes: false,      // Don't auto-convert types
  strict: true
});
addFormats(ajv);

// Define strict schema for order endpoint
const orderSchema = {
  type: 'object',
  additionalProperties: false,
  required: ['customer', 'items', 'shipping'],
  properties: {
    customer: {
      type: 'object',
      additionalProperties: false,
      required: ['id', 'email'],
      properties: {
        id: { type: 'string', pattern: '^[a-f0-9]{24}$' },
        email: { type: 'string', format: 'email', maxLength: 255 }
      }
    },
    items: {
      type: 'array',
      minItems: 1,
      maxItems: 50,
      items: {
        type: 'object',
        additionalProperties: false,
        required: ['productId', 'quantity'],
        properties: {
          productId: { type: 'string', pattern: '^[A-Z0-9]{8,16}$' },
          quantity: { type: 'integer', minimum: 1, maximum: 100 },
          options: {
            type: 'object',
            additionalProperties: false,
            properties: {
              size: { type: 'string', enum: ['S', 'M', 'L', 'XL'] },
              color: { type: 'string', pattern: '^[a-zA-Z]{2,20}$' }
            }
          }
        }
      }
    },
    shipping: {
      type: 'object',
      additionalProperties: false,
      required: ['address', 'method'],
      properties: {
        address: {
          type: 'object',
          additionalProperties: false,
          required: ['street', 'city', 'country', 'postalCode'],
          properties: {
            street: { type: 'string', minLength: 5, maxLength: 200 },
            city: { type: 'string', minLength: 2, maxLength: 100 },
            country: { type: 'string', pattern: '^[A-Z]{2}$' },
            postalCode: { type: 'string', pattern: '^[A-Z0-9\\-\\s]{3,15}$' }
          }
        },
        method: { type: 'string', enum: ['standard', 'express', 'overnight'] }
      }
    },
    couponCode: {
      type: 'string',
      pattern: '^[A-Z0-9]{5,20}$'
    }
  }
};

const validateOrder = ajv.compile(orderSchema);

// Defense Layer 3: Depth limiting middleware
const MAX_DEPTH = 5;

const checkDepth = (obj, currentDepth = 0) => {
  if (currentDepth > MAX_DEPTH) {
    return false;
  }
  if (obj && typeof obj === 'object') {
    for (const value of Object.values(obj)) {
      if (!checkDepth(value, currentDepth + 1)) {
        return false;
      }
    }
  }
  return true;
};

const depthLimiter = (req, res, next) => {
  if (!checkDepth(req.body)) {
    return res.status(400).json({
      error: 'Request body exceeds maximum nesting depth'
    });
  }
  next();
};

// Defense Layer 4: Schema validation middleware
const validateSchema = (validator) => (req, res, next) => {
  const valid = validator(req.body);

  if (!valid) {
    const errors = validator.errors.map(err => ({
      field: err.instancePath || err.params?.missingProperty,
      message: err.message
    }));

    // Log validation failures for monitoring
    console.warn('Schema validation failed', {
      ip: req.ip,
      path: req.path,
      errors: errors.slice(0, 5), // Limit logged errors
      timestamp: new Date().toISOString()
    });

    return res.status(400).json({
      error: 'Validation failed',
      details: errors.slice(0, 10) // Limit exposed errors
    });
  }
  next();
};

// Defense Layer 5: Business logic validation
const validateBusinessRules = async (req, res, next) => {
  const { customer, items, shipping } = req.body;

  try {
    // Verify customer exists and matches authenticated user
    if (customer.id !== req.user.id) {
      return res.status(403).json({ error: 'Customer ID mismatch' });
    }

    // Verify all products exist and are available
    const productIds = items.map(item => item.productId);
    const products = await getProducts(productIds);

    const unavailable = items.filter(item => {
      const product = products.find(p => p.id === item.productId);
      return !product || product.stock < item.quantity;
    });

    if (unavailable.length > 0) {
      return res.status(400).json({
        error: 'Some products are unavailable',
        unavailable: unavailable.map(i => i.productId)
      });
    }

    // Verify shipping destination is allowed
    const allowedCountries = ['US', 'CA', 'GB', 'DE', 'FR', 'AU'];
    if (!allowedCountries.includes(shipping.address.country)) {
      return res.status(400).json({ error: 'Shipping not available to this country' });
    }

    // Calculate and attach validated totals
    req.validatedOrder = {
      ...req.body,
      calculatedTotal: calculateTotal(items, products),
      validatedAt: new Date()
    };

    next();
  } catch (error) {
    console.error('Business validation error:', error);
    res.status(500).json({ error: 'Validation processing failed' });
  }
};

// Main order endpoint with all validation layers
app.post('/api/orders',
  depthLimiter,                    // Layer 3: Depth check
  validateSchema(validateOrder),   // Layer 4: Schema validation
  validateBusinessRules,           // Layer 5: Business logic
  async (req, res) => {
    try {
      // All validation passed - process the order
      const order = await createOrder(req.validatedOrder);

      // Audit log
      console.info('Order created', {
        orderId: order.id,
        userId: req.user.id,
        total: order.total,
        timestamp: new Date().toISOString()
      });

      res.status(201).json({
        success: true,
        orderId: order.id,
        total: order.total
      });
    } catch (error) {
      console.error('Order creation failed:', error);
      res.status(500).json({ error: 'Order processing failed' });
    }
  }
);

// Rate limiting for validation-heavy endpoints
const rateLimit = require('express-rate-limit');

const orderLimiter = rateLimit({
  windowMs: 15 * 60 * 1000,  // 15 minutes
  max: 50,                    // 50 orders per window
  message: { error: 'Too many order attempts' }
});

app.use('/api/orders', orderLimiter);

app.listen(3000);
```

**Defense in Depth Layers**:

1. **Parser-level protection**: JSON body size limits, strict parsing, prototype pollution prevention at parse time

2. **Schema validation (AJV)**: Strict type checking, format validation, additionalProperties:false strips unknown fields

3. **Depth limiting**: Prevents deeply nested payloads that cause resource exhaustion or bypass shallow validation

4. **Business logic validation**: Verifies ownership, existence of referenced entities, and business rules

5. **Rate limiting**: Prevents abuse of validation-heavy endpoints

**Additional Protections**:
- **Fail-safe defaults**: Missing optional fields get safe defaults, not dangerous ones
- **Immutable critical fields**: Order totals are calculated server-side, never trusted from client
- **Comprehensive logging**: All validation failures logged with context for security monitoring
- **Error sanitization**: Validation errors expose enough for debugging but not internal details
- **Array length limits**: Prevents resource exhaustion via massive arrays
